use chrono::{DateTime, Utc};
use uuid::Uuid;

use super::todo_title::TodoTitle;
use super::user::UserId;

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SomedayMaybeId(Uuid);

impl Default for SomedayMaybeId {
    fn default() -> Self {
        Self::new()
    }
}

impl SomedayMaybeId {
    pub fn new() -> Self {
        Self(Uuid::new_v4())
    }

    pub fn from_uuid(uuid: Uuid) -> Self {
        Self(uuid)
    }

    pub fn as_uuid(&self) -> &Uuid {
        &self.0
    }
}

/// A parked idea -- not committed to, but not forgotten.
/// No state machine: items are created, optionally edited, and either
/// activated (moved to inbox) or deleted.
#[derive(Debug, Clone)]
pub struct SomedayMaybeItem {
    id: SomedayMaybeId,
    user_id: UserId,
    title: TodoTitle,
    created_at: DateTime<Utc>,
}

impl SomedayMaybeItem {
    pub fn new(user_id: UserId, title: TodoTitle) -> Self {
        Self {
            id: SomedayMaybeId::new(),
            user_id,
            title,
            created_at: Utc::now(),
        }
    }

    pub fn from_parts(
        id: SomedayMaybeId,
        user_id: UserId,
        title: TodoTitle,
        created_at: DateTime<Utc>,
    ) -> Self {
        Self {
            id,
            user_id,
            title,
            created_at,
        }
    }

    pub fn id(&self) -> &SomedayMaybeId {
        &self.id
    }

    pub fn user_id(&self) -> &UserId {
        &self.user_id
    }

    pub fn title(&self) -> &TodoTitle {
        &self.title
    }

    pub fn created_at(&self) -> &DateTime<Utc> {
        &self.created_at
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn someday_maybe_id_is_unique() {
        let id1 = SomedayMaybeId::new();
        let id2 = SomedayMaybeId::new();
        assert_ne!(id1, id2);
    }

    #[test]
    fn someday_maybe_id_from_uuid_roundtrips() {
        let uuid = Uuid::new_v4();
        let id = SomedayMaybeId::from_uuid(uuid);
        assert_eq!(id.as_uuid(), &uuid);
    }

    #[test]
    fn new_someday_maybe_item_has_correct_fields() {
        let user_id = UserId::new();
        let title = TodoTitle::parse("Learn Esperanto".to_string()).unwrap();
        let item = SomedayMaybeItem::new(user_id.clone(), title);

        assert_eq!(item.user_id(), &user_id);
        assert_eq!(item.title().as_str(), "Learn Esperanto");
    }

    #[test]
    fn from_parts_reconstructs_item() {
        let id = SomedayMaybeId::new();
        let user_id = UserId::new();
        let title = TodoTitle::parse("Build a treehouse".to_string()).unwrap();
        let now = Utc::now();

        let item = SomedayMaybeItem::from_parts(id.clone(), user_id.clone(), title, now);

        assert_eq!(item.id(), &id);
        assert_eq!(item.user_id(), &user_id);
        assert_eq!(item.title().as_str(), "Build a treehouse");
        assert_eq!(item.created_at(), &now);
    }
}

use chrono::{DateTime, Utc};
use sqlx::{PgExecutor, PgPool};
use uuid::Uuid;

use crate::domain::{SomedayMaybeId, SomedayMaybeItem, TodoTitle, UserId};

struct SomedayMaybeRecord {
    id: Uuid,
    user_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
}

impl SomedayMaybeRecord {
    fn into_domain(self) -> SomedayMaybeItem {
        let id = SomedayMaybeId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        SomedayMaybeItem::from_parts(id, user_id, title, self.created_at)
    }
}

pub async fn insert_someday_maybe_item(
    executor: impl PgExecutor<'_>,
    item: &SomedayMaybeItem,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"INSERT INTO someday_maybe_items (id, user_id, title, created_at)
           VALUES ($1, $2, $3, $4 :: timestamptz)"#,
        item.id().as_uuid(),
        item.user_id().as_uuid(),
        item.title().as_str(),
        item.created_at() as &DateTime<Utc>,
    )
    .execute(executor)
    .await?;
    Ok(())
}

pub async fn find_someday_maybe_items_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<SomedayMaybeItem>, sqlx::Error> {
    let records = sqlx::query_as!(
        SomedayMaybeRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM someday_maybe_items
           WHERE user_id = $1
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: SomedayMaybeRecord| r.into_domain())
        .collect())
}

pub async fn find_someday_maybe_item_by_id(
    pool: &PgPool,
    item_id: &SomedayMaybeId,
) -> Result<Option<SomedayMaybeItem>, sqlx::Error> {
    let record: Option<SomedayMaybeRecord> = sqlx::query_as!(
        SomedayMaybeRecord,
        r#"SELECT id, user_id, title,
           created_at as "created_at: DateTime<Utc>"
           FROM someday_maybe_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r| r.into_domain()))
}

pub async fn delete_someday_maybe_item(
    executor: impl PgExecutor<'_>,
    item_id: &SomedayMaybeId,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM someday_maybe_items WHERE id = $1"#,
        item_id.as_uuid(),
    )
    .execute(executor)
    .await?;
    Ok(())
}

pub async fn count_someday_maybe_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM someday_maybe_items WHERE user_id = $1"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

pub async fn update_someday_maybe_title(
    pool: &PgPool,
    item_id: &SomedayMaybeId,
    title: &TodoTitle,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE someday_maybe_items SET title = $1 WHERE id = $2"#,
        title.as_str(),
        item_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

use sqlx::PgPool;

use crate::domain::{
    InboxItem, SomedayMaybeId, SomedayMaybeItem, TodoTitle, TodoTitleError, UserId,
};
use crate::infrastructure::inbox_repository;
use crate::infrastructure::someday_maybe_repository;

#[derive(Debug, thiserror::Error)]
pub enum AddSomedayMaybeError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

#[tracing::instrument(
    name = "add_someday_maybe_item",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn add_someday_maybe_item(
    pool: &PgPool,
    user_id: UserId,
    title: String,
) -> Result<SomedayMaybeItem, AddSomedayMaybeError> {
    let title = TodoTitle::parse(title)?;
    let item = SomedayMaybeItem::new(user_id, title);

    someday_maybe_repository::insert_someday_maybe_item(pool, &item)
        .await
        .map_err(|e| {
            AddSomedayMaybeError::Unexpected(anyhow::anyhow!(
                "Failed to insert someday/maybe item: {e}"
            ))
        })?;

    tracing::info!("Someday/maybe item added");
    Ok(item)
}

#[tracing::instrument(
    name = "list_someday_maybe_items",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn list_someday_maybe_items(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<SomedayMaybeItem>, anyhow::Error> {
    let items = someday_maybe_repository::find_someday_maybe_items_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch someday/maybe items: {e}"))?;

    Ok(items)
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteSomedayMaybeError {
    #[error("Someday/maybe item not found")]
    NotFound,
    #[error("Not authorized to delete this someday/maybe item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_someday_maybe_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_someday_maybe_item(
    pool: &PgPool,
    item_id: &SomedayMaybeId,
    user_id: &UserId,
) -> Result<(), DeleteSomedayMaybeError> {
    let item = someday_maybe_repository::find_someday_maybe_item_by_id(pool, item_id)
        .await
        .map_err(|e| DeleteSomedayMaybeError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteSomedayMaybeError::NotFound)?;

    if item.user_id() != user_id {
        return Err(DeleteSomedayMaybeError::Unauthorized);
    }

    someday_maybe_repository::delete_someday_maybe_item(pool, item_id)
        .await
        .map_err(|e| {
            DeleteSomedayMaybeError::Unexpected(anyhow::anyhow!(
                "Failed to delete someday/maybe item: {e}"
            ))
        })?;

    tracing::info!("Someday/maybe item deleted");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum UpdateSomedayMaybeError {
    #[error("Someday/maybe item not found")]
    NotFound,
    #[error("Not authorized to edit this someday/maybe item")]
    Unauthorized,
    #[error("Invalid title: {0}")]
    InvalidTitle(TodoTitleError),
    #[error(transparent)]
    Unexpected(anyhow::Error),
}

#[tracing::instrument(
    name = "update_someday_maybe_title",
    skip(pool, new_title),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn update_someday_maybe_title(
    pool: &PgPool,
    item_id: &SomedayMaybeId,
    user_id: &UserId,
    new_title: String,
) -> Result<(), UpdateSomedayMaybeError> {
    let item = someday_maybe_repository::find_someday_maybe_item_by_id(pool, item_id)
        .await
        .map_err(|e| UpdateSomedayMaybeError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(UpdateSomedayMaybeError::NotFound)?;

    if item.user_id() != user_id {
        return Err(UpdateSomedayMaybeError::Unauthorized);
    }

    let title = TodoTitle::parse(new_title).map_err(UpdateSomedayMaybeError::InvalidTitle)?;

    someday_maybe_repository::update_someday_maybe_title(pool, item_id, &title)
        .await
        .map_err(|e| {
            UpdateSomedayMaybeError::Unexpected(anyhow::anyhow!(
                "Failed to update someday/maybe item: {e}"
            ))
        })?;

    tracing::info!("Someday/maybe item updated");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum ActivateSomedayMaybeError {
    #[error("Someday/maybe item not found")]
    NotFound,
    #[error("Not authorized to activate this someday/maybe item")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "activate_someday_maybe_item",
    skip(pool),
    fields(item_id = %item_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn activate_someday_maybe_item(
    pool: &PgPool,
    item_id: &SomedayMaybeId,
    user_id: &UserId,
) -> Result<InboxItem, ActivateSomedayMaybeError> {
    let mut tx = pool.begin().await.map_err(|e| {
        ActivateSomedayMaybeError::Unexpected(anyhow::anyhow!("Failed to begin transaction: {e}"))
    })?;

    let item = someday_maybe_repository::find_someday_maybe_item_by_id(pool, item_id)
        .await
        .map_err(|e| ActivateSomedayMaybeError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(ActivateSomedayMaybeError::NotFound)?;

    if item.user_id() != user_id {
        return Err(ActivateSomedayMaybeError::Unauthorized);
    }

    let inbox_item = InboxItem::new(user_id.clone(), item.title().clone());

    inbox_repository::insert_inbox_item(&mut *tx, &inbox_item)
        .await
        .map_err(|e| {
            ActivateSomedayMaybeError::Unexpected(anyhow::anyhow!(
                "Failed to insert inbox item: {e}"
            ))
        })?;

    someday_maybe_repository::delete_someday_maybe_item(&mut *tx, item_id)
        .await
        .map_err(|e| {
            ActivateSomedayMaybeError::Unexpected(anyhow::anyhow!(
                "Failed to delete someday/maybe item: {e}"
            ))
        })?;

    tx.commit().await.map_err(|e| {
        ActivateSomedayMaybeError::Unexpected(anyhow::anyhow!("Failed to commit transaction: {e}"))
    })?;

    tracing::info!("Someday/maybe item activated (moved to inbox)");
    Ok(inbox_item)
}

