 46→fn build_view(item: &crate::domain::SomedayMaybeItem) -> SomedayMaybeView {
 47→    SomedayMaybeView {
 48→        id: item.id().as_uuid().to_string(),
 49→        title: item.title().as_str().to_string(),
 50→        date_added: item.created_at().format("%b %d, %Y").to_string(),
 51→        date_added_iso: item.created_at().to_rfc3339(),
 52→    }
 53→}
