 55→pub async fn get_someday_maybe(
 56→    AuthenticatedUser(user_id): AuthenticatedUser,
 57→    State(pool): State<PgPool>,
 58→) -> Result<Response, SomedayMaybeError> {
 59→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
 60→        .await
 61→        .map_err(SomedayMaybeError::Unexpected)?;
 62→
 63→    let items = someday_maybe_service::list_someday_maybe_items(&pool, &user_id)
 64→        .await
 65→        .map_err(SomedayMaybeError::Unexpected)?;
 66→
 67→    let item_views: Vec<SomedayMaybeView> = items.iter().map(build_view).collect();
 68→
 69→    let template = SomedayMaybeTemplate {
 70→        current_page: "someday_maybe",
 71→        inbox_count,
 72→        items: item_views,
 73→        error_message: None,
 74→    };
 75→    Ok(Html(template.render()?).into_response())
 76→}
 77→
 78→#[derive(serde::Deserialize)]
 79→pub struct AddSomedayMaybeForm {
 80→    pub title: String,
 81→}
 82→
 83→pub async fn post_someday_maybe(
 84→    AuthenticatedUser(user_id): AuthenticatedUser,
 85→    State(pool): State<PgPool>,
 86→    headers: HeaderMap,
 87→    Form(form): Form<AddSomedayMaybeForm>,
 88→) -> Result<Response, SomedayMaybeError> {
 89→    let htmx = is_htmx_request(&headers);
 90→
 91→    if form.title.trim().is_empty() {
 92→        if htmx {
 93→            return Ok(StatusCode::NO_CONTENT.into_response());
 94→        }
 95→        return Ok(Redirect::to("/someday-maybe").into_response());
 96→    }
 97→
 98→    match someday_maybe_service::add_someday_maybe_item(&pool, user_id.clone(), form.title).await {
 99→        Ok(item) => {
100→            if htmx {
101→                let template = SomedayMaybeItemTemplate {
102→                    item: build_view(&item),
103→                };
104→                let body = template.render().map_err(SomedayMaybeError::Render)?;
105→                Ok(htmx_response_with_announce(Html(body), "Idea parked"))
106→            } else {
107→                Ok(Redirect::to("/someday-maybe").into_response())
108→            }
109→        }
110→        Err(AddSomedayMaybeError::InvalidTitle(title_err)) => {
111→            let user_facing = match title_err {
112→                TodoTitleError::Empty => {
113→                    if htmx {
114→                        return Ok(StatusCode::NO_CONTENT.into_response());
115→                    }
116→                    return Ok(Redirect::to("/someday-maybe").into_response());
117→                }
118→                TodoTitleError::TooLong { max, .. } => {
119→                    format!("That title is too long (max {max} characters)")
120→                }
121→            };
122→            render_someday_maybe_with_error(&pool, &user_id, &user_facing).await
123→        }
124→        Err(AddSomedayMaybeError::Unexpected(err)) => Err(SomedayMaybeError::Unexpected(err)),
125→    }
126→}
127→
128→async fn render_someday_maybe_with_error(
129→    pool: &PgPool,
130→    user_id: &crate::domain::UserId,
131→    error_message: &str,
132→) -> Result<Response, SomedayMaybeError> {
133→    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
134→        .await
135→        .map_err(SomedayMaybeError::Unexpected)?;
136→
137→    let items = someday_maybe_service::list_someday_maybe_items(pool, user_id)
138→        .await
139→        .map_err(SomedayMaybeError::Unexpected)?;
140→
141→    let item_views: Vec<SomedayMaybeView> = items.iter().map(build_view).collect();
142→
143→    let template = SomedayMaybeTemplate {
144→        current_page: "someday_maybe",
145→        inbox_count,
146→        items: item_views,
147→        error_message: Some(error_message.to_string()),
148→    };
149→    let body = template.render().map_err(SomedayMaybeError::Render)?;
150→    Ok((StatusCode::UNPROCESSABLE_ENTITY, Html(body)).into_response())
151→}
152→
